func:
// Obtener el device_code ingresado
let deviceCode = msg.payload.trim();

if (!deviceCode) {
    node.status({fill: "red", shape: "ring", text: "ID vacío"});
    return [null, null];  // No envía nada
}

// Consulta SQL
msg.topic = `
    SELECT name, status, energy_capability, temperature_capability 
    FROM device 
    WHERE device_code = ?
`;

msg.payload = [deviceCode];  // Parámetro seguro contra inyección SQL

return msg;

flow.set(msg.topic, msg.payload === 'true');
// Trigger update to datos
return msg;

var msgs = [];
if (flow.get('energy_capability')) {
    msgs.push({payload: '100 kWh'}); // Placeholder
} else {
    msgs.push({payload: ''});
}
if (flow.get('temperature_capability')) {
    msgs.push({payload: '25°C'}); // Placeholder
} else {
    msgs.push({payload: ''});
}
return [msgs[0], msgs[1]];

flow.set('modbus_type', msg.payload);
msg.modbus_type = msg.payload;
return msg;

if (msg.payload && msg.payload.type === "RTU") {

    const puertoDesdeScan = (global.get("modbus_rtu_config") || {}).serialPort;
    const puerto = msg.payload.port || puertoDesdeScan || "/dev/ttyACM0";

    const cfg = {
        connectorType:  "serial",
        serialPort:     puerto,
        serialBaudrate: Number(msg.payload.baud) || 9600,
        serialParity:   msg.payload.parity || "none",
        serialDatabits: Number(msg.payload.data_bits) || 8,
        serialStopbits: Number(msg.payload.stop_bits) || 1,
        fc:       Number(msg.payload.fc) || 4,
        unitId:   Number(msg.payload.slave_id) || 1,
        address:  Number(msg.payload.address) || 0,
        quantity: Number(msg.payload.quantity) || 10
    };

    global.set("modbus_rtu_config", cfg);

    const connectorPayload = {
        connectorType:  "serial",
        serialPort:     cfg.serialPort,
        serialBaudrate: cfg.serialBaudrate,
        serialDatabits: cfg.serialDatabits,
        serialStopbits: cfg.serialStopbits,
        serialParity:   cfg.serialParity,
        serialType:     "RTU-BUFFERED"
    };

    node.status({fill:"green", shape:"dot", text:"RTU OK → " + cfg.serialPort + " @ " + cfg.serialBaudrate});
    node.warn("Config Modbus guardada:");
    node.warn(cfg);

    // Salida 1 → Flex Connector (inmediato)
    // Salida 2 → trigger primera lectura (después del delay)
    return [{ payload: connectorPayload }, { payload: {} }];

} else {
    node.warn("Payload no es config RTU válida: " + JSON.stringify(msg.payload));
    node.status({fill:"grey", shape:"ring", text:"No RTU"});
    return null;
}

let textoOriginal = msg.status?.text || "desconocido";
let mensaje = textoOriginal;
let color = "grey";

// Mapeo de estados comunes del modbus-flex-connector
switch (textoOriginal.toLowerCase()) {
    case "connected":
    case "active":
        mensaje = "Conectado";
        color = "green";
        break;
    case "connecting":
    case "reconnecting":
        mensaje = "Conectando...";
        color = "orange";
        break;
    case "disconnected":
    case "failed":
    case "error":
        mensaje = "Error / Desconectado";
        color = "red";
        break;
    default:
        mensaje = textoOriginal;
        color = "grey";
}

// Guardar global para uso en otros nodos si necesitas
global.set("conexionModbus", { texto: mensaje, color: color, original: textoOriginal });

// Preparar para el dashboard
msg.payload = mensaje;
msg.color = color;

return msg;

const cfg = global.get("modbus_rtu_config") || {};

if (!cfg.serialPort) {
    node.status({fill:"red", shape:"ring", text:"Esperando config..."});
    return null;
}

msg.payload = {
    fc:       cfg.fc || 4,
    unitid:   cfg.unitId || 1,
    address:  cfg.address || 0,
    quantity: cfg.quantity || 10
};

node.status({fill:"blue", shape:"dot", text:"FC" + msg.payload.fc + " → " + cfg.serialPort});
return msg;

if (!msg.payload || !Array.isArray(msg.payload) || msg.payload.length < 10) {
    node.status({fill:"red", shape:"ring", text:"Sin datos válidos"});
    return null;
}

const deviceId = global.get("dispositivoId") || null;

if (!deviceId) {
    node.status({fill:"yellow", shape:"ring", text:"Falta ID dispositivo"});
    return null;
}

const data = msg.payload;
const voltage     = data[0] / 10.0;
const current     = ((data[2] << 16) | data[1]) / 1000.0;
const power       = ((data[4] << 16) | data[3]) / 10.0;
const energy      = (data[6] << 16) | data[5];
const frequency   = data[7] / 10.0;
const powerFactor = data[8] / 100.0;
const alarm       = data[9] === 0xFFFF;

msg.topic   = `NanoFreeze/${deviceId}/Sensores`;
msg.payload = {
    timestamp:   new Date().toISOString(),
    deviceId:    deviceId,
    power:       power,
    energy_wh:   energy,
    energy_kwh:  parseFloat((energy / 1000).toFixed(3)),
    voltage:     voltage,
    current:     current,
    frequency:   frequency,
    powerFactor: powerFactor,
    alarm:       alarm
};

node.status({fill:"green", shape:"dot", text:`${deviceId} → ${power}W`});
return msg;

if (msg.payload && msg.payload.length > 0) {
    let row = msg.payload[0];  // Primera fila (debería ser única por device_code)

    // Enviar a los textos
    let nameMsg = { payload: row.name || "No encontrado" };
    let statusMsg = { payload: row.status || "Desconocido" };

    // Enviar a switches (true/false como booleano)
    let energyMsg = { topic: "energy_capability", payload: !!row.energy_capability };
    let tempMsg = { topic: "temperature_capability", payload: !!row.temperature_capability };

    node.status({fill: "green", shape: "dot", text: "Device encontrado"});

    return [nameMsg, statusMsg, energyMsg, tempMsg];
} else {
    node.status({fill: "yellow", shape: "ring", text: "Device no encontrado"});

    return [
        { payload: "No encontrado" },   // name
        { payload: "No encontrado" },   // status
        { topic: "energy_capability", payload: false },
        { topic: "temperature_capability", payload: false }
    ];
}

let textoOriginal = msg.status?.text || "desconocido";
let mensaje = "Desconocido";
let color = "grey";

// Mapeo de claves comunes de estado MQTT (i18n)
switch (textoOriginal.toLowerCase()) {
    case "node-red:common.status.connected":
        mensaje = "Conectado";
        color = "green";
        break;

    case "node-red:common.status.connecting":
    case "node-red:common.status.reconnecting":
        mensaje = "Conectando...";
        color = "orange";
        break;

    case "node-red:common.status.disconnected":
        mensaje = "Desconocido";
        color = "red";
        break;

    default:
        if (textoOriginal.toLowerCase().includes("error") || 
            textoOriginal.toLowerCase().includes("failed") || 
            textoOriginal.toLowerCase().includes("refused")) {
            mensaje = "Error de conexión";
            color = "red";
        } else {
            mensaje = textoOriginal;
            color = "grey";
        }
}

// Guardamos el estado para el dashboard y el router
global.set("conexionMQTT", { 
    texto: mensaje, 
    color: color, 
    original: textoOriginal 
});

// ────────────────────────────────────────────────
//           DETECTAR RECONEXIÓN
// ────────────────────────────────────────────────
const estadoAnterior = flow.get("mqtt_estado_anterior") || "desconectado";
const estadoActual = textoOriginal.toLowerCase();

flow.set("mqtt_estado_anterior", estadoActual);

// Solo cuando PASA A CONECTADO
let dispararBuffer = false;
if (estadoActual.includes("connected") && !estadoAnterior.includes("connected")) {
    dispararBuffer = true;
    node.status({fill:"blue", shape:"ring", text:"Reconectado → enviando buffer"});
}

// Guardamos también mqtt_online (para compatibilidad con tu router actual)
global.set("mqtt_online", mensaje === "Conectado");

// Salidas:
// 1 = para dashboard (siempre)
// 2 = para disparar lectura de buffer (solo al reconectar)
return [
    { payload: mensaje, color: color },           // salida 1 → dashboard
    dispararBuffer ? { topic: `
        SELECT id, uuid, payload, intentos
        FROM buffer_iot
        WHERE enviado = 0
        ORDER BY id ASC
        LIMIT 1
    ` } : null                                      // salida 2 → sqlite leer pendiente
];

let online = global.get("mqtt_online") || false;

node.warn("TOPIC: " + msg.topic);
node.warn("PAYLOAD: " + JSON.stringify(msg.payload, null, 2));
node.warn("online: " + online);

if (online) {
    node.warn("ENVIANDO POR SALIDA 1");
    // Guardar copia del mensaje en flow context para comparar
    flow.set("ultimo_mensaje_enviado", {
        timestamp: Date.now(),
        topic: msg.topic,
        payload: JSON.parse(JSON.stringify(msg.payload))
    });
    return [msg, null];
} else {
    node.warn("GUARDANDO EN BUFFER");
    msg.topic = "INSERT INTO buffer_iot (uuid, payload) VALUES (?, ?)";
    msg.payload = [
        Date.now().toString(),
        JSON.stringify(msg.payload)
    ];
    return [null, msg];
}

if (!msg.responseBuffer || !msg.responseBuffer.data) {
    return null;
}

const data = {
    timestamp: new Date().toISOString(),
    deviceId: "DEV-10-1",
    registro1: msg.responseBuffer.data[0] || 0,
    registro2: msg.responseBuffer.data[1] || 0,
    registro3: msg.responseBuffer.data[2] || 0,
    registro4: msg.responseBuffer.data[3] || 0
};

const uuid = Date.now().toString();
const json = JSON.stringify(data).replace(/'/g, "''");

msg.topic = `
INSERT INTO buffer_iot (uuid, payload)
VALUES ('${uuid}', '${json}')
`;

return msg;

const puertos = msg.payload
    .trim()
    .split("\n")
    .filter(p => p.length > 0)
    .map(p => ({ label: p.trim(), value: p.trim() }));

if (puertos.length === 0) {
    puertos.push({ label: "Sin puertos detectados", value: "" });
}

msg.payload = puertos;
msg.topic = "options";

global.set("puertos_disponibles", puertos);
node.status({fill:"green", shape:"dot", text: puertos.length + " puerto(s) detectado(s)"});
return msg;

if (msg.topic === "options") return null;

const cfg = global.get("modbus_rtu_config") || {};
cfg.serialPort = msg.payload;
global.set("modbus_rtu_config", cfg);

node.status({fill:"blue", shape:"dot", text: "Puerto: " + msg.payload});
node.warn("Puerto guardado: " + msg.payload);
return null;

let mac = msg.payload.toString().trim().replace(/:/g,'').toUpperCase();
flow.set('serial', mac);
return { topic: "$aws/certificates/create/json", payload: "" };

flow.set('deviceCert', msg.payload.certificatePem);
flow.set('deviceKey', msg.payload.privateKey);

let serial = flow.get('serial');

return {
    topic: "$aws/provisioning-templates/IbisaTemplate/provision/json",
    payload: {
        certificateOwnershipToken: msg.payload.certificateOwnershipToken,
        parameters: {
            SerialNumber: serial
        }
    }
};

let cert = flow.get('deviceCert');
let key = flow.get('deviceKey');
let thingName = msg.payload.thingName;

return [
    { payload: cert, filename: "/home/pi/certificados/device.pem.crt" },
    { payload: key, filename: "/home/pi/certificados/device.private.key" },
    { payload: thingName, filename: "/home/pi/certificados/thing-name.txt" }
];

node.warn("Reconexión detectada → esperando 4 segundos para estabilizar MQTT");
return new Promise(resolve => {
    setTimeout(() => {
        resolve([{
            topic: `SELECT id, uuid, payload, intentos FROM buffer_iot WHERE enviado = 0 ORDER BY id ASC LIMIT 1`
        }]);
    }, 4000);
});

node.warn("Preparar y enviar pendiente - entrada recibida");

if (msg.payload && Array.isArray(msg.payload) && msg.payload.length > 0) {
    const row = msg.payload[0];
    node.warn("Pendiente encontrado ID: " + row.id);

    msg.buffer_id   = row.id;
    msg.intentos    = row.intentos || 0;

    try {
        msg.payload = JSON.parse(row.payload);
    } catch (err) {
        node.warn("Error parseando JSON del buffer → ID " + row.id + " → se descarta");
        return [null, null, {
            topic: "SELECT id, uuid, payload, intentos FROM buffer_iot WHERE enviado = 0 ORDER BY id ASC LIMIT 1"
        }];
    }

    msg.topic = `NanoFreeze/${msg.payload.deviceId}/Sensores`;

    node.warn("Listo para enviar a MQTT:");
    node.warn(msg.payload);
    node.warn("MQTT topic: " + msg.topic);
    node.warn("📤 Enviando a MQTT y a marcar OK");

    return [msg, msg, null];

} else {
    node.warn("No hay más pendientes. Iniciando limpieza de registros enviados...");

    return [null, null, {
        topic: "DELETE FROM buffer_iot WHERE enviado = 1",
        clean_trigger: true,
        clean_reason: "buffer_vaciado"
    }];
}

if (typeof msg.buffer_id === "undefined" || isNaN(msg.buffer_id)) {
    node.warn("ABORT: buffer_id inválido o ausente → " + JSON.stringify(msg.buffer_id));
    return null;
}

const id = Number(msg.buffer_id);     // fuerza a número
const intentos = Number(msg.intentos || 0);

if (isNaN(id) || id <= 0) {
    node.error("ID inválido después de conversión: " + msg.buffer_id);
    return null;
}

node.warn(`Intentando marcar como enviado → ID=${id} (tipo=${typeof id}), intentos=${intentos}`);

msg.topic = `UPDATE buffer_iot 
             SET enviado = 1, 
                 fecha_envio = CURRENT_TIMESTAMP, 
                 intentos = ${intentos} 
             WHERE id = ${id}`;
msg.payload = []; 

node.warn("UPDATE preparado → payload: " + JSON.stringify(msg.payload));

return msg;

node.warn("Fallo al enviar pendiente → ID: " + (msg.buffer_id || "desconocido"));

let intentos = (msg.intentos || 0) + 1;

if (!msg.buffer_id) {
    node.warn("No hay buffer_id → no se puede actualizar intentos");
} else {
    msg.topic = `UPDATE buffer_iot SET intentos = ? WHERE id = ?`;
    msg.payload = [intentos, parseInt(msg.buffer_id, 10)];
}

node.warn("Intentos ahora: " + intentos + " → continuamos con el siguiente");

return {
    topic: `SELECT id, uuid, payload, intentos FROM buffer_iot WHERE enviado = 0 ORDER BY id ASC LIMIT 1`
};

node.warn("Resultado recibido para confirmación:");

if (!msg.payload || msg.payload.length === 0) {
    node.warn("No hay más pendientes - FIN DEL PROCESO");
    return null;
}

const row = msg.payload[0];
node.warn(`ID encontrado: ${row.id}, intentos: ${row.intentos}`);

return msg;

const id = msg.buffer_id;

if (id === undefined) {
    node.warn("❌ buffer_id no presente, abortando");
    return null;
}

node.warn(`✅ UPDATE ejecutado para ID ${id}, confiando en que fue exitoso`);

return {
    topic: "SELECT id, uuid, payload, intentos FROM buffer_iot WHERE enviado = 0 ORDER BY id ASC LIMIT 1"
};

const id = msg.buffer_id ? parseInt(msg.buffer_id, 10) : null;

if (!id) {
    node.warn("❌ No hay buffer_id válido para verificar");
    return null;
}

node.warn(`Verificando ID ${id} (tipo: ${typeof id})`);

if (!msg.payload || msg.payload.length === 0) {
    node.warn(`❌ No se encontró el ID ${id} en la BD`);

    return {
        buffer_id: id,
        diagnostic: true,
        topic: "SELECT id FROM buffer_iot ORDER BY id"
    };
}

const estado = msg.payload[0].enviado;
node.warn(`✅ ID ${id} encontrado, enviado = ${estado}`);

if (estado === 1) {
    return {
        topic: "SELECT id, uuid, payload, intentos FROM buffer_iot WHERE enviado = 0 ORDER BY id ASC LIMIT 1"
    };
} else {
    node.warn(`❌ El UPDATE no funcionó, el ID ${id} sigue con enviado = ${estado}`);
    return {
        topic: "SELECT id, uuid, payload, intentos FROM buffer_iot WHERE enviado = 0 ORDER BY id ASC LIMIT 1"
    };
}

// Verificar resultado del UPDATE - VERSIÓN CORREGIDA
node.warn("=== VERIFICACIÓN DE FILAS AFECTADAS ===");
node.warn(`UPDATE para ID ${msg.buffer_id}`);
node.warn(`Payload recibido: ${JSON.stringify(msg.payload)}`);

// En node-red-node-sqlite, el resultado a veces tiene propiedad .changes
if (msg.payload && typeof msg.payload === 'object') {
    // Intentar obtener el número de filas afectadas
    const changes = msg.payload.changes || 
                    (msg.payload[0] && msg.payload[0].changes) || 
                    "desconocido";

    node.warn(`Filas afectadas: ${changes}`);

    if (changes === 0 || changes === "desconocido") {
        node.warn(`⚠️ No se pudo confirmar si el UPDATE afectó filas`);
        node.warn(`Array vacío = operación completada, pero sin certeza de cambios`);
    } else {
        node.warn(`✅ UPDATE exitoso: ${changes} fila(s) modificada(s)`);
    }
}

// AHORA LA PARTE IMPORTANTE: Verificar realmente con un SELECT
// Vamos a hacer una consulta para ver el estado actual del ID 3
node.warn(`🔍 Verificando estado real del ID ${msg.buffer_id} en la BD...`);

// Crear mensaje para SELECT de verificación
let verifyMsg = {
    buffer_id: msg.buffer_id,
    intentos: msg.intentos,
    topic: "SELECT enviado FROM buffer_iot WHERE id = ?",
    payload: [msg.buffer_id]
};

return verifyMsg;

node.warn("=== IDs ENCONTRADOS EN LA BD ===");
if (msg.payload && msg.payload.length > 0) {
    msg.payload.forEach(row => {
        node.warn(`ID: ${row.id} (tipo: ${typeof row.id})`);
    });

    const ids = msg.payload.map(row => row.id);
    node.warn(`IDs disponibles: ${ids.join(', ')}`);

    const row3 = msg.payload.find(row => row.id === 3);
    if (row3) {
        node.warn(`✅ El ID 3 SÍ existe en la BD`);
        node.warn(`ID 3 es tipo: ${typeof row3.id}, valor: ${row3.id}`);
        node.warn(`✅ El ID es NUMBER, debería funcionar con número.`);
    } else {
        node.warn(`❌ El ID 3 NO existe en la BD`);
    }
}

node.warn("🔍 Continuando con la búsqueda del siguiente pendiente...");

return {
    topic: "SELECT id, uuid, payload, intentos FROM buffer_iot WHERE enviado = 0 ORDER BY id ASC LIMIT 1"
};

// Analizar verificación del UPDATE
node.warn("=== RESULTADO DE VERIFICACIÓN ===");
node.warn(`ID: ${msg.buffer_id}`);

if (!msg.payload || msg.payload.length === 0) {
    node.warn(`❌ ERROR: No se encontró el ID ${msg.buffer_id} en la BD`);
    return null;
}

const estado = msg.payload[0].enviado;
node.warn(`Estado actual del ID ${msg.buffer_id}: enviado = ${estado}`);

if (estado === 1) {
    node.warn(`✅ VERIFICADO: ID ${msg.buffer_id} está marcado como enviado`);
    // Buscar siguiente pendiente
    return {
        topic: "SELECT id, uuid, payload, intentos FROM buffer_iot WHERE enviado = 0 ORDER BY id ASC LIMIT 1"
    };
} else {
    node.warn(`❌ PROBLEMA: ID ${msg.buffer_id} sigue con enviado = ${estado}`);
    node.warn(`El UPDATE NO funcionó - revisar permisos o estructura de la BD`);

    // Para no quedar en loop infinito, saltar este ID
    node.warn(`⏩ Saltando ID ${msg.buffer_id} y buscando siguiente...`);
    return {
        topic: `SELECT id, uuid, payload, intentos FROM buffer_iot WHERE enviado = 0 AND id > ${msg.buffer_id} ORDER BY id ASC LIMIT 1`
    };
}

node.warn("UPDATE confirmado → buscando siguiente pendiente");

return {
    topic: `
        SELECT id, uuid, payload, intentos 
        FROM buffer_iot 
        WHERE enviado = 0 
        ORDER BY id ASC 
        LIMIT 1
    `
};

// Verificar que el UPDATE realmente ocurrió
return {
    topic: "SELECT enviado, intentos, fecha_envio FROM buffer_iot WHERE id = ?",
    payload: [Number(msg.buffer_id || 0)]
};
